/**
 * Extracts only the icons actually used in the source code from @iconify/json
 * and generates a TypeScript bundle that pre-registers them with @iconify/svelte.
 * This prevents any runtime CDN fetches.
 *
 * Used standalone (CI/Docker) and as a Vite plugin (dev server).
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

export function generateIconBundle(rootDir) {
	const srcDir = join(rootDir, 'src');
	const jsonDir = join(rootDir, 'node_modules', '@iconify', 'json', 'json');
	const outFile = join(srcDir, 'lib', 'icon-bundle.ts');

	// Scan all .svelte and .ts files for icon references like:
	//   icon="prefix:name"          (Svelte attributes)
	//   'prefix:name'               (JS string literals)
	//   "prefix:name"               (JS string literals)
	const icons = new Set();
	const pattern = /(?:icon=)?"([a-z][\w-]*:[a-z][\w-]*)"|'([a-z][\w-]*:[a-z][\w-]*)'/g;

	function scan(d) {
		for (const entry of readdirSync(d, { withFileTypes: true })) {
			const full = join(d, entry.name);
			if (entry.isDirectory() && entry.name !== 'node_modules') {
				scan(full);
			} else if (entry.name.endsWith('.svelte') || entry.name.endsWith('.ts')) {
				// Skip the output file itself
				if (full === outFile) continue;
				const content = readFileSync(full, 'utf-8');
				let match;
				while ((match = pattern.exec(content)) !== null) {
					icons.add(match[1] || match[2]);
				}
			}
		}
	}

	scan(srcDir);

	// Group by prefix
	const byPrefix = {};
	for (const icon of icons) {
		const [prefix, name] = icon.split(':');
		if (!byPrefix[prefix]) byPrefix[prefix] = [];
		byPrefix[prefix].push(name);
	}

	// Build minimal icon sets from @iconify/json
	const collections = [];
	for (const [prefix, names] of Object.entries(byPrefix)) {
		const jsonFile = join(jsonDir, `${prefix}.json`);
		let fullSet;
		try {
			fullSet = JSON.parse(readFileSync(jsonFile, 'utf-8'));
		} catch {
			console.warn(`[icon-bundle] Warning: icon set "${prefix}" not found, skipping`);
			continue;
		}

		const subset = {
			prefix: fullSet.prefix,
			icons: {},
			width: fullSet.width,
			height: fullSet.height
		};

		for (const name of names) {
			if (fullSet.icons[name]) {
				subset.icons[name] = fullSet.icons[name];
			} else if (fullSet.aliases && fullSet.aliases[name]) {
				const alias = fullSet.aliases[name];
				const parent = alias.parent;
				if (fullSet.icons[parent]) {
					subset.icons[parent] = fullSet.icons[parent];
					if (!subset.aliases) subset.aliases = {};
					subset.aliases[name] = alias;
				}
			} else {
				console.warn(`[icon-bundle] Warning: icon "${prefix}:${name}" not found`);
			}
		}

		collections.push(subset);
	}

	// Generate TypeScript
	const ts = `// Auto-generated by scripts/generate-icon-bundle.mjs
// Pre-registers icons so @iconify/svelte never fetches from CDN.
import { addCollection } from '@iconify/svelte';

${collections.map((col, i) => `const c${i} = ${JSON.stringify(col)} as const;`).join('\n')}

${collections.map((_, i) => `addCollection(c${i});`).join('\n')}
`;

	const existing = (() => {
		try {
			return readFileSync(outFile, 'utf-8');
		} catch {
			return '';
		}
	})();
	if (existing !== ts) {
		writeFileSync(outFile, ts);
		console.log(`[icon-bundle] Generated ${icons.size} icons from ${collections.length} sets`);
		return true;
	}
	return false;
}

// Run standalone when executed directly
const isMain = process.argv[1] && fileURLToPath(import.meta.url).includes(process.argv[1]);
if (isMain) {
	generateIconBundle(join(__dirname, '..'));
}
